INSERT INTO `wp_fs_saved_replies` (`id`,`created_by`,`mailbox_id`,`product_id`,`title`,`content`,`created_at`,`updated_at`) VALUES('13',NULL,NULL,NULL,'How to book a tutorial','Pick a slot on the expert calendar, complete checkout, and manage from /my-tutorials. You will receive an email + .ics file.','2025-10-23 14:22:07','2025-10-23 14:22:07');
